import java.io.*;
import java.util.*;

public class Main {
    public static void main(String[] args) throws Exception {
        BufferedReader br = new BufferedReader(new InputStreamReader(System.in));
        StringBuilder sb = new StringBuilder();
        int T = Integer.parseInt(br.readLine().trim());
        for (int t = 0; t < T; t++) {
            StringTokenizer st = new StringTokenizer(br.readLine());
            double num1 = Double.parseDouble(st.nextToken());
            double num2 = Double.parseDouble(st.nextToken());
            char op = br.readLine().trim().charAt(0);
            double result = 0.0;
            switch (op) {
                case '+': result = num1 + num2; break;
                case '-': result = num1 - num2; break;
                case '*': result = num1 * num2; break;
                case '/': if (num2 != 0) result = num1 / num2; else result = 0; break;
            }
            sb.append(String.format(Locale.US, "%.2f", result)).append('\n');
        }
        System.out.print(sb.toString());
    }
}

