import sys

def main():
    data = sys.stdin.read().strip().splitlines()
    if not data:
        return
    t = int(data[0].strip())
    idx = 1
    out = []
    for _ in range(t):
        num1, num2 = map(float, data[idx].split())
        idx += 1
        op = data[idx].strip()
        idx += 1
        if op == '+':
            res = num1 + num2
        elif op == '-':
            res = num1 - num2
        elif op == '*':
            res = num1 * num2
        else:  # '/'
            if num2 != 0:
                res = num1 / num2
            else:
                res = 0
        out.append(f"{res:.2f}")
    sys.stdout.write("\n".join(out))

if __name__ == "__main__":
    main()

